import{c as a,Q as l,j as e,m as o}from"./chunks/framework.5k1Nei9d.js";const S=JSON.parse('{"title":"IPA 自签与 Sideload","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/ios-sideload.md","filePath":"tutorials/ios-sideload.md"}'),i={name:"tutorials/ios-sideload.md"};function r(d,t,s,h,n,c){return l(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="ipa-自签与-sideload" tabindex="-1">IPA 自签与 Sideload <a class="header-anchor" href="#ipa-自签与-sideload" aria-label="Permalink to &quot;IPA 自签与 Sideload&quot;">​</a></h1><h2 id="什么是-sideload" tabindex="-1">什么是 Sideload？ <a class="header-anchor" href="#什么是-sideload" aria-label="Permalink to &quot;什么是 Sideload？&quot;">​</a></h2><p>Sideload（侧载）是指不通过 App Store，直接从 IPA 文件安装应用到 iOS 设备。</p><h2 id="三种方案对比" tabindex="-1">三种方案对比 <a class="header-anchor" href="#三种方案对比" aria-label="Permalink to &quot;三种方案对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>方案</th><th>有效期</th><th>限制</th><th>推荐度</th></tr></thead><tbody><tr><td><strong>TrollStore</strong></td><td>永久</td><td>仅限特定 iOS 版本</td><td>⭐⭐⭐⭐⭐</td></tr><tr><td><strong>AltStore</strong></td><td>7 天（免费）/ 1 年（付费）</td><td>需连接电脑续签</td><td>⭐⭐⭐⭐</td></tr><tr><td><strong>Sideloadly</strong></td><td>7 天</td><td>需连接电脑续签</td><td>⭐⭐⭐</td></tr></tbody></table><h2 id="altstore-教程" tabindex="-1">AltStore 教程 <a class="header-anchor" href="#altstore-教程" aria-label="Permalink to &quot;AltStore 教程&quot;">​</a></h2><h3 id="安装-altstore" tabindex="-1">安装 AltStore <a class="header-anchor" href="#安装-altstore" aria-label="Permalink to &quot;安装 AltStore&quot;">​</a></h3><ol><li>下载 <a href="https://altstore.io/" target="_blank" rel="noreferrer">AltServer</a>（Windows/macOS）</li><li>安装 iCloud（Windows 需要）</li><li>连接 iPhone，打开 AltServer</li><li>菜单栏点击 AltServer → Install AltStore → 选择你的设备</li><li>输入 Apple ID 和密码</li><li>手机上信任企业证书：设置 → 通用 → VPN 与设备管理</li></ol><h3 id="通过-altstore-安装-ipa" tabindex="-1">通过 AltStore 安装 IPA <a class="header-anchor" href="#通过-altstore-安装-ipa" aria-label="Permalink to &quot;通过 AltStore 安装 IPA&quot;">​</a></h3><ol><li>下载 <code>.ipa</code> 文件到手机</li><li>用 AltStore 打开</li><li>输入 Apple ID 签名</li><li>等待安装完成</li></ol><h3 id="自动续签" tabindex="-1">自动续签 <a class="header-anchor" href="#自动续签" aria-label="Permalink to &quot;自动续签&quot;">​</a></h3><p>AltStore 在后台会自动续签（需连接同一 Wi-Fi），7 天内无需手动操作。</p><h2 id="sideloadly-教程" tabindex="-1">Sideloadly 教程 <a class="header-anchor" href="#sideloadly-教程" aria-label="Permalink to &quot;Sideloadly 教程&quot;">​</a></h2><ol><li>下载 <a href="https://sideloadly.io/" target="_blank" rel="noreferrer">Sideloadly</a></li><li>连接 iPhone，打开 Sideloadly</li><li>拖入 IPA 文件</li><li>输入 Apple ID</li><li>点击 Start</li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>免费 Apple ID 签名的应用 7 天后会失效，需要重新签名。 付费开发者账号（$99/年）签名有效期为 1 年。</p></div>',15)])])}const A=a(i,[["render",r]]);export{S as __pageData,A as default};
